import React from 'react';

const TransactionList = ({ transactions, onDelete }) => {
  return (
    <div className="overflow-x-auto">
      <table className="w-full bg-white rounded-2xl shadow-2xl">
        <thead>
          <tr className="bg-gradient-to-r from-gray-50 to-gray-100 border-b-2 border-gray-200">
            <th className="p-6 text-left text-lg font-black text-gray-900">Date</th>
            <th className="p-6 text-left text-lg font-black text-gray-900">Category</th>
            <th className="p-6 text-right text-lg font-black text-gray-900">Amount</th>
            <th className="p-6 text-right text-lg font-black text-gray-900">Type</th>
            <th className="p-6 text-right text-lg font-black text-gray-900">Actions</th>
          </tr>
        </thead>
        <tbody>
          {transactions.map((t) => (
            <tr key={t.id} className="hover:bg-gray-50 transition-colors border-b border-gray-100">
              <td className="p-6 font-semibold text-gray-900">{new Date(t.date).toLocaleDateString()}</td>
              <td className="p-6 font-medium text-gray-700 capitalize">{t.category}</td>
              <td className="p-6 font-bold text-2xl">
                <span className={t.type === 'income' ? 'text-green-600' : 'text-red-600'}>
                  {t.type === 'income' ? '+' : '-'}${t.amount.toLocaleString()}
                </span>
              </td>
              <td className="p-6">
                <span className={`px-4 py-2 rounded-full text-sm font-bold ${
                  t.type === 'income' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                }`}>
                  {t.type.toUpperCase()}
                </span>
              </td>
              <td className="p-6">
                <button 
                  onClick={() => onDelete(t.id)}
                  className="bg-red-500 hover:bg-red-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-200"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
          {transactions.length === 0 && (
            <tr>
              <td colSpan="5" className="p-12 text-center text-gray-500 text-xl">
                No transactions yet. Add some using the form above!
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default TransactionList;
